let METADATA={platforms:[]}; let STRATEGY_CONTROL={managed_by_admin:false,allowed_strategies:[],all_strategies:[]}; let DASHBOARD_CACHE={trades:[],summary:{},executionLogs:[],botSessions:[],connectors:[]};
const EXECUTION_LOG_LIMIT=50; const EXECUTION_LOG_REFRESH_MS=5*60*1000;
const parseCsv=(v)=>String(v||'').split(',').map(x=>x.trim()).filter(Boolean);
const timeframeToMinutes=(timeframe)=>{const clean=String(timeframe||'').trim().toLowerCase();const map={"1m":1,"3m":3,"5m":5,"15m":15,"30m":30,"1h":60,"2h":120,"4h":240,"6h":360,"8h":480,"12h":720,"1d":1440};return map[clean]||5;};
const setNodeText=(id,value)=>{const node=document.getElementById(id);if(node)node.textContent=value;};
const safeNumber=(value)=>Number(value||0);
function reportMarkup(items=[]){return items.filter(Boolean).map((item)=>`<article class="quantum-report-item"><strong>${item.title||'-'}</strong><small>${item.body||'-'}</small></article>`).join('');}
function parseApiError(error){const raw=String(error?.message||'Error inesperado');try{const payload=JSON.parse(raw);if(payload?.detail)return Array.isArray(payload.detail)?payload.detail.map(d=>d.msg||JSON.stringify(d)).join(' | '):String(payload.detail);}catch(_e){}return raw;}
async function api(url,options={}){const res=await fetch(url,{headers:{'Content-Type':'application/json'},credentials:'same-origin',...options});if(!res.ok) throw new Error(await res.text());return res.json();}
const allowedPlatforms=()=>METADATA.platforms.filter((p)=>p.is_enabled_global&&p.grant?.is_enabled).map((p)=>p.platform);

function initTabs(rootSel,panelPrefix){const buttons=document.querySelectorAll(`${rootSel} .tab-btn`);buttons.forEach((btn)=>btn.addEventListener('click',()=>{buttons.forEach((b)=>b.classList.toggle('active',b===btn));document.querySelectorAll(`[id^="${panelPrefix}"]`).forEach((panel)=>panel.classList.toggle('active',panel.id===`${panelPrefix}${btn.dataset.tab}`));}));}

function renderProfile(user){const name=document.getElementById('profile-name');if(name)name.value=user.name||'';const email=document.getElementById('profile-email');if(email)email.value=user.email||'';const phone=document.getElementById('profile-phone');if(phone)phone.value=user.phone||'';const tgEnabled=document.getElementById('profile-telegram-enabled');if(tgEnabled)tgEnabled.checked=Boolean(user.telegram_alerts_enabled);const tgBot=document.getElementById('profile-telegram-bot-key');if(tgBot)tgBot.value=user.has_telegram_bot_key?'••••••••':'';const tgChat=document.getElementById('profile-telegram-chat-id');if(tgChat)tgChat.value=user.telegram_chat_id||'';const lang=document.getElementById('profile-alert-language');if(lang)lang.value=user.alert_language||'es';const mode=document.getElementById('trade-amount-mode');if(mode)mode.value=user.trade_amount_mode||'fixed_usd';const fixed=document.getElementById('fixed-trade-amount-usd');if(fixed)fixed.value=Number(user.fixed_trade_amount_usd||10);const pct=document.getElementById('trade-balance-percent');if(pct)pct.value=Number(user.trade_balance_percent||10);const profileTitle=document.getElementById('profile-title');if(profileTitle)profileTitle.textContent=user.is_admin?'Cuenta administrativa':'Perfil de usuario';}
function renderUserConfigReport(user){const node=document.getElementById('user-config-report');if(!node)return;const strategyCount=(STRATEGY_CONTROL.allowed_strategies||[]).length;node.innerHTML=reportMarkup([{title:'Perfil de ejecución',body:`${user.trade_amount_mode==='balance_percent'?'Sizing por porcentaje de balance':'Sizing fijo por operación'} · Idioma alertas: ${String(user.alert_language||'es').toUpperCase()}`},{title:'Canal de alertas',body:user.telegram_alerts_enabled?`${user.telegram_ready?'Telegram validado y activo':'Telegram activo, pendiente validar'}${user.telegram_chat_id?` · Chat ${user.telegram_chat_id}`:''}`:'Telegram inactivo · Alertas locales únicamente'},{title:'Universo operativo',body:`${allowedPlatforms().length} plataformas habilitadas por admin · ${strategyCount||Object.keys(STRATEGY_LIBRARY).length} estrategias disponibles`}]);setNodeText('user-config-state',user.name?`Profile · ${user.name}`:'Profile loaded');}
function selectedMarketType(){const option=document.querySelector('#run-connector-select option:checked');return option?.dataset?.marketType||'spot';}
async function saveProfile(e){e.preventDefault();const fd=new FormData(e.target);const feedback=document.getElementById('profile-feedback');const botKeyRaw=String(fd.get('telegram_bot_key')||'').trim();const botKey=botKeyRaw.startsWith('••••')?undefined:botKeyRaw;const chatIdRaw=String(fd.get('telegram_chat_id')||'').trim();const chatId=chatIdRaw==='****'?undefined:chatIdRaw;try{await api('/api/me',{method:'PUT',body:JSON.stringify({name:fd.get('name'),phone:fd.get('phone'),telegram_alerts_enabled:fd.get('telegram_alerts_enabled')==='on',telegram_bot_key:botKey,telegram_chat_id:chatId,alert_language:fd.get('alert_language')})});if(feedback){feedback.textContent='Perfil actualizado con éxito.';feedback.className='status-msg status-ok';}const me=await api('/api/me');renderProfile(me);renderUserConfigReport(me);}catch(err){if(feedback){feedback.textContent=parseApiError(err);feedback.className='status-msg status-error';}}}

async function saveTradeAmountSettings(e){e.preventDefault();const fd=new FormData(e.target);const feedback=document.getElementById('profile-trade-amount-feedback');try{await api('/api/me',{method:'PUT',body:JSON.stringify({trade_amount_mode:fd.get('trade_amount_mode'),fixed_trade_amount_usd:Number(fd.get('fixed_trade_amount_usd')),trade_balance_percent:Number(fd.get('trade_balance_percent'))})});if(feedback){feedback.textContent='Monto por operación actualizado.';feedback.className='status-msg status-ok';}const me=await api('/api/me');renderProfile(me);renderUserConfigReport(me);}catch(err){if(feedback){feedback.textContent=parseApiError(err);feedback.className='status-msg status-error';}}}
async function testTelegram(){const feedback=document.getElementById('telegram-test-feedback');if(feedback){feedback.textContent='Enviando prueba de Telegram...';feedback.className='status-msg';}try{const result=await api('/api/me/telegram/test',{method:'POST'});if(feedback){feedback.textContent=result.message||'Mensaje de prueba enviado.';feedback.className='status-msg status-ok';}}catch(err){if(feedback){feedback.textContent=parseApiError(err);feedback.className='status-msg status-error';}}}

function renderStrategySelect(){const select=document.querySelector('select[name="strategy_slug"]');if(!select)return;const market=selectedMarketType();select.innerHTML=Object.entries(STRATEGY_LIBRARY).filter(([_,meta])=>!meta.marketTypes||meta.marketTypes.includes(market)).map(([slug,meta])=>`<option value="${slug}">${meta.name}</option>`).join('');if(!select.value&&select.options.length)select.value=select.options[0].value;}
function renderStrategyLibrary(){const node=document.getElementById('strategy-library');if(!node)return;node.innerHTML=Object.entries(STRATEGY_LIBRARY).map(([slug,meta])=>`<button class="connector-item strategy-card strategy-card-compact" type="button" data-slug="${slug}"><strong>${meta.name}</strong><small class="hint">${meta.summary}</small></button>`).join('');node.querySelectorAll('.strategy-card').forEach((btn)=>btn.addEventListener('click',()=>openStrategyInfo(btn.dataset.slug)));}
function openStrategyInfo(slug){const meta=STRATEGY_LIBRARY[slug];if(!meta)return;document.getElementById('strategy-modal-title').textContent=meta.name;document.getElementById('strategy-modal-summary').textContent=meta.summary;document.getElementById('strategy-modal-usecase').textContent=meta.useCase;document.getElementById('strategy-modal-timeframes').textContent=meta.timeframes;document.getElementById('strategy-modal-tips').innerHTML=meta.tips.map(t=>`<li>${t}</li>`).join('');document.getElementById('strategy-info-modal').classList.remove('hidden');}
const closeStrategyInfo=()=>document.getElementById('strategy-info-modal')?.classList.add('hidden');

