function connectorSetupGuide(platform){const guide=CONNECTOR_SETUP_GUIDES[platform];if(!guide)return '';return `<aside class="term-box setup-box" id="connector-setup-${platform}"><h4>${guide.title}</h4><ol>${guide.steps.map((step)=>`<li>${step}</li>`).join('')}</ol><p class="setup-warning">${guide.warning}</p></aside>`;}
function activatePlatformTab(platform,allowed){const tabs=document.getElementById('platform-tabs');if(!tabs)return;tabs.querySelectorAll('.tab-btn').forEach((btn)=>btn.classList.toggle('active',btn.dataset.platform===platform));(allowed||[]).forEach((p)=>document.getElementById(`platform-panel-${p}`)?.classList.toggle('active',p===platform));}

function renderPlatformTabs(){const allowed=allowedPlatforms();const tabs=document.getElementById('platform-tabs');const panels=document.getElementById('platform-panels');if(!tabs||!panels)return;tabs.innerHTML=allowed.map((p,i)=>`<div class="platform-tab-entry"><button class="tab-btn ${i===0?'active':''}" type="button" data-platform="${p}">${p.toUpperCase()} y estrategias</button><a class="tab-link-guide" href="#connector-setup-${p}" data-platform-guide="${p}">Guía</a></div>`).join('');panels.innerHTML=allowed.map((platform,i)=>`<section class="platform-panel ${i===0?'active':''}" id="platform-panel-${platform}">${platformForm(platform)}</section>`).join('');tabs.querySelectorAll('.tab-btn').forEach(btn=>btn.addEventListener('click',()=>activatePlatformTab(btn.dataset.platform,allowed)));tabs.querySelectorAll('[data-platform-guide]').forEach((link)=>link.addEventListener('click',(e)=>{e.preventDefault();const platform=link.dataset.platformGuide;activatePlatformTab(platform,allowed);document.getElementById(`connector-setup-${platform}`)?.scrollIntoView({behavior:'smooth',block:'start'});}));}
function connectorTerminology(){return `<aside class="term-box"><h4>Terminología y recomendaciones</h4><ul><li><strong>Paper:</strong> simulación sin dinero real (ideal para validar estrategia).</li><li><strong>Live:</strong> órdenes reales con capital real (usar solo tras validar en paper).</li><li><strong>Signal:</strong> solo recibe/genera señales sin ejecutar automáticamente.</li><li><strong>Spot:</strong> compra/venta directa del activo.</li><li><strong>Futures:</strong> derivados con apalancamiento (mayor riesgo).</li><li><strong>Combinación recomendada:</strong> inicia en <span class="market-mini">Paper + Spot</span> y escala a <span class="market-mini">Live + Spot</span> antes de usar futures.</li></ul></aside>`;}
function platformForm(platform){const meta=METADATA.platforms.find(p=>p.platform===platform)||{};const marketTypes=PLATFORM_MARKET_TYPES[platform]||['spot'];const fields=(PLATFORM_FIELD_MAP[platform]||[]).map((f)=>`<label>${f.label}<input data-field="${f.key}" data-target="${f.target}" ${f.type?`type="${f.type}"`:''} ${f.step?`step="${f.step}"`:''} ${f.required?'required':''}></label>`).join('');return `<div class="card"><h2>${meta.display_name||platform.toUpperCase()}</h2><p class="hint">Solo visible porque está activado por admin para tu cuenta.</p><div class="connector-layout"><form class="connector-form form-grid" data-platform="${platform}"><label>Etiqueta<input name="label" required placeholder="Cuenta principal"></label><label>Modo de operación<select name="mode"><option value="paper">paper (simulado)</option><option value="live">live (real)</option><option value="signal">signal (solo señales)</option></select></label><label>Tipo de mercado<select name="market_type">${marketTypes.map(m=>`<option value="${m}">${m}</option>`).join('')}</select></label><label>Símbolos<input name="symbols" placeholder="BTC/USDT,ETH/USDT"></label><div class="form-grid">${fields}</div><button class="btn primary" type="submit">Guardar conector ${platform.toUpperCase()}</button></form><div class="connector-help-stack">${connectorTerminology()}${connectorSetupGuide(platform)}</div></div><div id="list-${platform}" class="stack" style="margin-top:12px;"></div></div>`;}
function bindPlatformForms(){document.querySelectorAll('.connector-form').forEach((form)=>form.addEventListener('submit',async(e)=>{e.preventDefault();const fd=new FormData(form);const config={},secrets={};form.querySelectorAll('[data-field]').forEach((i)=>{if(!i.value) return; (i.dataset.target==='secrets'?secrets:config)[i.dataset.field]=i.type==='number'?Number(i.value):i.value;});try{await api('/api/connectors',{method:'POST',body:JSON.stringify({platform:form.dataset.platform,label:fd.get('label'),mode:fd.get('mode'),market_type:fd.get('market_type'),symbols:parseCsv(fd.get('symbols')),config,secrets})});form.reset();await refreshDashboard();}catch(err){setRunFeedback(parseApiError(err),'error');}}));}

function selectedRunConnectorIds(){return Array.from(document.getElementById('run-connector-select')?.selectedOptions||[]).map(o=>Number(o.value));}
function applyStrategyControlUI(){const select=document.querySelector('select[name="strategy_slug"]');const hint=document.getElementById('strategy-managed-hint');if(!select)return;const allowed=STRATEGY_CONTROL.allowed_strategies?.length?STRATEGY_CONTROL.allowed_strategies:Array.from(select.options).map(o=>o.value);Array.from(select.options).forEach(option=>{option.hidden=!allowed.includes(option.value);option.disabled=!allowed.includes(option.value);});if(!allowed.includes(select.value)&&allowed.length) select.value=allowed[0];select.disabled=!!STRATEGY_CONTROL.managed_by_admin;if(hint) hint.textContent=STRATEGY_CONTROL.managed_by_admin?'Estrategia gestionada por administrador para esta cuenta.':'Puedes elegir entre las estrategias habilitadas para tu cuenta.';renderStrategyEditors();}


function strategyMetaFor(slug){return STRATEGY_LIBRARY[slug]||{name:slug};}
function renderStrategyEditors(){const node=document.getElementById('profile-strategy-checks');if(!node)return;const allowed=STRATEGY_CONTROL.allowed_strategies?.length?STRATEGY_CONTROL.allowed_strategies:Object.keys(STRATEGY_LIBRARY);node.innerHTML=Object.keys(STRATEGY_LIBRARY).map((slug)=>{const meta=strategyMetaFor(slug);const checked=allowed.includes(slug)?'checked':'';const disabled=STRATEGY_CONTROL.managed_by_admin?'disabled':'';return `<label class="checkbox"><input type="checkbox" name="allowed_strategies" value="${slug}" ${checked} ${disabled}> ${meta.name}</label>`;}).join('');const feedbackNode=document.getElementById('profile-strategy-feedback');if(feedbackNode){feedbackNode.className='hint';feedbackNode.textContent=STRATEGY_CONTROL.managed_by_admin?'Estas estrategias son gestionadas por el administrador.':'Selecciona las estrategias activas que quieres mantener habilitadas.';}}
async function saveStrategySelection(e){e.preventDefault();const form=e.target;const feedback=document.getElementById('profile-strategy-feedback');const allowed=Array.from(form.querySelectorAll('input[name="allowed_strategies"]:checked')).map((n)=>n.value);try{const data=await api('/api/strategy-control',{method:'PUT',body:JSON.stringify({allowed_strategies:allowed})});STRATEGY_CONTROL=data;applyStrategyControlUI();if(feedback){feedback.textContent='Estrategias activas actualizadas.';feedback.className='status-msg status-ok';}}catch(err){if(feedback){feedback.textContent=parseApiError(err);feedback.className='status-msg status-error';}}}

function daysForFilter(v){if(v==='day')return 1;if(v==='month')return 30;return 7;}
function detectUserLocale(){return (navigator.languages&&navigator.languages[0])||navigator.language||'es-ES';}
function formatLocalDateTime(value){if(!value)return '-';const d=new Date(value);if(Number.isNaN(d.getTime()))return '-';return d.toLocaleString(detectUserLocale());}
function formatLocalTimeNow(){return new Date().toLocaleTimeString(detectUserLocale());}
function minutesSince(value){if(!value)return Number.POSITIVE_INFINITY;const time=new Date(value).getTime();if(Number.isNaN(time))return Number.POSITIVE_INFINITY;return Math.max(0,(Date.now()-time)/60000);}
function syncExecutiveBadge(){const map={day:'Día',week:'Semana',month:'Mes'};const value=document.getElementById('trade-range-filter')?.value||'week';setNodeText('reports-range-badge',map[value]||'Semana');}
function renderDecisionTelemetry(){const node=document.getElementById('decision-breakdown-panel');if(!node)return;const logs=Array.isArray(DASHBOARD_CACHE.executionLogs)?DASHBOARD_CACHE.executionLogs:[];if(!logs.length){node.innerHTML=reportMarkup([{title:'Sin telemetría reciente',body:'Ejecuta una estrategia o espera el próximo refresh de logs para poblar este panel.'}]);setNodeText('decision-report-state','0 eventos');return;}const decisionCount=logs.reduce((acc,item)=>{const key=String(decisionLabel(item)||'sin_decision').toLowerCase();acc[key]=(acc[key]||0)+1;return acc;},{});const topDecisions=Object.entries(decisionCount).sort((a,b)=>b[1]-a[1]).slice(0,3);const lastLog=logs[0];node.innerHTML=reportMarkup([{title:'Última evaluación',body:`${decisionLabel(lastLog)} · ${lastLog.symbol||'Sin símbolo'} · ${formatLocalDateTime(lastLog.created_at)}`},...topDecisions.map(([label,count])=>({title:label.replaceAll('_',' '),body:`${count} eventos en la ventana de ${Math.min(logs.length,EXECUTION_LOG_LIMIT)} logs analizada.`}))]);setNodeText('decision-report-state',`${logs.length} eventos`);}
function renderQuantumStatus(){const summary=DASHBOARD_CACHE.summary||{};const connectors=Array.isArray(DASHBOARD_CACHE.connectors)?DASHBOARD_CACHE.connectors:[];const trades=Array.isArray(DASHBOARD_CACHE.trades)?DASHBOARD_CACHE.trades:[];const logs=Array.isArray(DASHBOARD_CACHE.executionLogs)?DASHBOARD_CACHE.executionLogs:[];const liveConnectors=connectors.filter((item)=>item?.is_enabled).length;const totalConnectors=Math.max(connectors.length,1);const recentLogMinutes=minutesSince(logs[0]?.created_at);const syncHealthy=recentLogMinutes<=15;const healthScore=Math.max(8,Math.min(99,Math.round(((liveConnectors/totalConnectors)*55)+(summary.total_trades?20:8)+(syncHealthy?16:4)+(safeNumber(summary.realized_pnl)>=0?8:3))));setNodeText('quant-health-score',`${healthScore}%`);setNodeText('quant-sync-status',syncHealthy?'Sincronizado':'A revisar');setNodeText('quant-live-connectors',String(liveConnectors));setNodeText('quant-last-heartbeat',logs[0]?.created_at?formatLocalDateTime(logs[0].created_at):'Sin eventos');const pill=document.getElementById('quant-health-pill');if(pill){pill.textContent=healthScore>=75?'Operativo':healthScore>=45?'Estable':'Crítico';pill.classList.toggle('pill-on',healthScore>=75);pill.classList.toggle('pill-off',healthScore<75);}const statusStrip=document.getElementById('quant-status-strip');if(statusStrip){statusStrip.innerHTML=reportMarkup([{title:'Cobertura de conectores',body:`${liveConnectors} activos de ${connectors.length} configurados · ${allowedPlatforms().length} plataformas con acceso concedido.`},{title:'Sesiones automatizadas',body:`${(DASHBOARD_CACHE.botSessions||[]).filter((item)=>item?.is_active).length} bots activos · ${(DASHBOARD_CACHE.botSessions||[]).length} sesiones registradas.`},{title:'Exposición PnL',body:`${safeNumber(summary.realized_pnl).toFixed(2)} USD realizados · ${safeNumber(summary.winning_trades)} ganadas / ${safeNumber(summary.losing_trades)} perdidas.`}]);}const connectorPanel=document.getElementById('connector-health-panel');if(connectorPanel){connectorPanel.innerHTML=connectors.length?reportMarkup(connectors.slice(0,6).map((item)=>({title:`${item.label||'Conector'} · ${item.platform||'-'}`,body:`${item.is_enabled?'Activo':'Inactivo'} · ${item.mode||'-'} / ${item.market_type||'-'} · ${(Array.isArray(item.symbols)?item.symbols.length:0)} símbolos monitoreados`}))):reportMarkup([{title:'Sin conectores',body:'Crea al menos un conector para visualizar estado operativo por canal.'}]);}const execPanel=document.getElementById('executive-report-panel');if(execPanel){execPanel.innerHTML=reportMarkup([{title:'Actividad reciente',body:`${trades.length} trades históricos cargados · ${logs.length} logs operativos disponibles para auditoría rápida.`},{title:'Distribución por plataformas',body:Object.entries(summary.platforms||{}).length?Object.entries(summary.platforms||{}).map(([platform,count])=>`${platform}: ${count}`).join(' · '):'Sin actividad por plataforma todavía.'},{title:'Cadencia del reporte',body:`Rango activo: ${document.getElementById('reports-range-badge')?.textContent||'Semana'} · Última actualización UI: ${formatLocalTimeNow()}`}]);}}
function detectSessionMarketType(item){const raw=[item.mode,item.market_type,item.connector_mode,item.connector_label,item.connector_name].filter(Boolean).join(' ').toLowerCase();return raw.includes('future')?'futures':'spot';}
function sortedSymbols(symbols){return (Array.isArray(symbols)?symbols:[]).map((s)=>String(s||'').trim()).filter(Boolean).sort((a,b)=>a.localeCompare(b));}
function renderTrades(){const range=document.getElementById('trade-range-filter')?.value||'week';const days=daysForFilter(range);const since=Date.now()-days*24*60*60*1000;const trades=DASHBOARD_CACHE.trades.filter((t)=>new Date(t.created_at).getTime()>=since);const tbody=document.querySelector('#trades-table tbody');if(tbody){tbody.innerHTML=trades.map(t=>{const inv=(Number(t.quantity)||0)*(Number(t.price)||0);const pnl=Number(t.pnl)||0;return `<tr><td>${formatLocalDateTime(t.created_at)}</td><td>${t.platform}</td><td>${t.symbol}</td><td>${inv.toFixed(2)}</td><td>${pnl>=0?'Ganó':'Perdió'}</td><td>${pnl.toFixed(2)}</td></tr>`;}).join('');}
const totalInv=trades.reduce((a,t)=>a+(Number(t.quantity)||0)*(Number(t.price)||0),0);const wins=trades.filter((t)=>(Number(t.pnl)||0)>=0).length;const avg=trades.length?trades.reduce((a,t)=>a+(Number(t.pnl)||0),0)/trades.length:0;const metrics=document.getElementById('trade-metrics');if(metrics){metrics.innerHTML=`<div class="metric"><small>Operaciones</small><strong>${trades.length}</strong></div><div class="metric"><small>Inversión</small><strong>${totalInv.toFixed(2)}</strong></div><div class="metric"><small>Ganadas</small><strong>${wins}</strong></div><div class="metric"><small>Promedio ganancia</small><strong>${avg.toFixed(2)}</strong></div>`;}}

function renderEconomicSummary(){const sessions=DASHBOARD_CACHE.botSessions||[];const activeSessions=sessions.filter((s)=>s&&s.is_active);const apps=new Set(activeSessions.map((s)=>String(s.platform||'').toLowerCase()).filter(Boolean));const strategyPnl={};activeSessions.forEach((session)=>{const slug=session.strategy_slug||'unknown';if(!strategyPnl[slug])strategyPnl[slug]={name:strategyName(slug),pnl:0,trades:0};(DASHBOARD_CACHE.trades||[]).forEach((trade)=>{if(String(trade.strategy_slug||'')!==String(slug))return;strategyPnl[slug].pnl+=Number(trade.pnl||0);strategyPnl[slug].trades+=1;});});const avgSymbols=activeSessions.length?activeSessions.reduce((acc,s)=>acc+(Array.isArray(s.symbols)?s.symbols.length:0),0)/activeSessions.length:0;const appsEl=document.getElementById('eco-active-apps');const symbolsEl=document.getElementById('eco-symbols-per-app');const strategiesEl=document.getElementById('eco-active-strategies');if(appsEl)appsEl.textContent=String(apps.size);if(symbolsEl)symbolsEl.textContent=avgSymbols.toFixed(1);if(strategiesEl)strategiesEl.textContent=String(Object.keys(strategyPnl).length);const list=document.getElementById('strategy-performance-list');if(!list)return;const ranked=Object.values(strategyPnl).sort((a,b)=>Math.abs(b.pnl)-Math.abs(a.pnl));if(!ranked.length){list.innerHTML='<small class="hint">Aún no hay rendimiento por estrategia. Activa bots para ver el panel.</small>';return;}list.innerHTML=ranked.map((item)=>{const pct=Math.max(-100,Math.min(100,item.pnl));const positive=item.pnl>=0;return `<div class="strategy-performance-item"><div><strong>${item.name}</strong><small class="hint">${item.trades} trades</small></div><div class="strategy-performance-metric"><span class="${positive?'ticker-up':'ticker-down'}">${item.pnl.toFixed(2)}%</span><div class="strategy-performance-bar"><span style="width:${Math.abs(pct)}%;" class="${positive?'is-up':'is-down'}"></span></div></div></div>`;}).join('');}
function candleToText(candle){if(!candle||typeof candle!=='object')return '-';const o=Number(candle.open||0).toFixed(4);const h=Number(candle.high||0).toFixed(4);const l=Number(candle.low||0).toFixed(4);const c=Number(candle.close||0).toFixed(4);return `O:${o} H:${h} L:${l} C:${c}`;}
function candleFromNotes(note){if(!note||typeof note!=='object')return null;return note.candle||note?.scanner?.candle||null;}
function decisionLabel(item){const decision=String(item?.notes?.decision||'').toLowerCase();if(decision==='buy')return 'Compró';if(decision==='sell')return 'Vendió';if(decision==='no_action')return 'Sin acción';return '-';}
function setExecutionLogsMeta(message){const meta=document.getElementById('execution-logs-refresh-meta');if(meta)meta.textContent=message;}

function strategyName(slug){return STRATEGY_LIBRARY[slug]?.name||slug;}
function botStatusLabel(session){if(!session.is_active)return 'Pausado';if(session.last_status==='ok')return 'Activo';if(session.last_status==='error')return `Error: ${session.last_error||'-'}`;if(session.last_status==='scheduled')return 'Programado';return session.last_status||'Activo';}
async function setBotSessionActive(id,isActive){await api(`/api/bot-sessions/${id}`,{method:'PUT',body:JSON.stringify({is_active:isActive})});await refreshBotSessions();}
async function deleteBotSession(id){await api(`/api/bot-sessions/${id}`,{method:'DELETE'});await refreshBotSessions();}
function activeConnectorForMarket(){const selected=selectedRunConnectorIds();if(selected.length){const picked=(DASHBOARD_CACHE.connectors||[]).find((c)=>c.id===selected[0]);if(picked)return picked;}return (DASHBOARD_CACHE.connectors||[]).find((c)=>c.is_enabled)||(DASHBOARD_CACHE.connectors||[])[0]||null;}
function renderLiveStrategiesPanel(){const panel=document.getElementById('strategies-live-panel');const countNode=document.getElementById('strategies-live-count');if(!panel)return;const sessions=(DASHBOARD_CACHE.botSessions||[]).filter((item)=>item.is_active);if(countNode)countNode.textContent=`${sessions.length} activas`;if(!sessions.length){panel.innerHTML='<small class="hint">No hay estrategias en ejecución ahora mismo.</small>';return;}const grouped={};sessions.forEach((item)=>{const platform=(item.platform||'sin app').toUpperCase();const market=detectSessionMarketType(item);if(!grouped[platform])grouped[platform]={spot:[],futures:[]};grouped[platform][market].push(item);});panel.innerHTML=Object.entries(grouped).sort((a,b)=>a[0].localeCompare(b[0])).map(([platform,markets])=>{const marketBlock=(type,label)=>{const rows=(markets[type]||[]).slice().sort((a,b)=>strategyName(a.strategy_slug).localeCompare(strategyName(b.strategy_slug)));if(!rows.length){return `<div class="strategy-live-market"><strong>${label}</strong><small class="hint">Sin estrategias activas.</small></div>`;}return `<div class="strategy-live-market"><strong>${label} · ${rows.length}</strong><ul>${rows.map((item)=>`<li>${strategyName(item.strategy_slug)} · ${sortedSymbols(item.symbols).join(', ')||'-'}</li>`).join('')}</ul></div>`;};return `<article class="strategy-live-app"><h4>${platform}</h4><div class="strategy-live-market-grid">${marketBlock('spot','Spot')}${marketBlock('futures','Futures')}</div></article>`;}).join('');}
async function editBotSession(id){const current=(DASHBOARD_CACHE.botSessions||[]).find((item)=>item.id===id);if(!current)return;const modal=document.createElement('div');modal.className='modal';modal.innerHTML=`<div class="modal-card card strategy-modal-card"><div class="modal-head"><h3>Editar estrategia activa</h3><button class="btn" type="button" id="close-edit-session">Cerrar</button></div><form id="edit-session-form" class="form-grid"><label>Timeframe<input name="timeframe" value="${current.timeframe||'5m'}"/></label><label>Símbolos (coma)<input name="symbols" value="${(current.symbols||[]).join(',')}"/></label><label>Take Win<div class="row-wrap"><select name="take_profit_mode"><option value="percent" ${(current.take_profit_mode||'percent')==='percent'?'selected':''}>%</option><option value="usdt" ${(current.take_profit_mode||'percent')==='usdt'?'selected':''}>USDT</option></select><input name="take_profit_value" type="number" step="0.1" min="0.1" value="${Number(current.take_profit_value||1.5)}"/></div></label><label>Stop Loss<div class="row-wrap"><select name="stop_loss_mode"><option value="percent" ${(current.stop_loss_mode||'percent')==='percent'?'selected':''}>%</option><option value="usdt" ${(current.stop_loss_mode||'percent')==='usdt'?'selected':''}>USDT</option></select><input name="stop_loss_value" type="number" step="0.1" min="0.1" value="${Number(current.stop_loss_value||1.0)}"/></div></label><label>Trailing Stop<div class="row-wrap"><select name="trailing_stop_mode"><option value="percent" ${(current.trailing_stop_mode||'percent')==='percent'?'selected':''}>%</option><option value="usdt" ${(current.trailing_stop_mode||'percent')==='usdt'?'selected':''}>USDT</option></select><input name="trailing_stop_value" type="number" step="0.1" min="0.1" value="${Number(current.trailing_stop_value||0.8)}"/></div></label><label class="checkbox"><input type="checkbox" name="indicator_exit_enabled" ${current.indicator_exit_enabled?'checked':''}/> Cierre por indicador</label><button class="btn primary" type="submit">Guardar cambios</button></form></div>`;document.body.appendChild(modal);const close=()=>modal.remove();modal.querySelector('#close-edit-session').addEventListener('click',close);modal.addEventListener('click',(e)=>{if(e.target===modal)close();});modal.querySelector('#edit-session-form').addEventListener('submit',async(e)=>{e.preventDefault();const fd=new FormData(e.target);const timeframe=String(fd.get('timeframe')||'5m');const interval=timeframeToMinutes(timeframe);await api(`/api/bot-sessions/${id}`,{method:'PUT',body:JSON.stringify({timeframe,symbols:parseCsv(fd.get('symbols')),interval_minutes:interval,take_profit_mode:fd.get('take_profit_mode'),take_profit_value:Number(fd.get('take_profit_value')),stop_loss_mode:fd.get('stop_loss_mode'),stop_loss_value:Number(fd.get('stop_loss_value')),trailing_stop_mode:fd.get('trailing_stop_mode'),trailing_stop_value:Number(fd.get('trailing_stop_value')),indicator_exit_enabled:fd.get('indicator_exit_enabled')==='on'})});close();await refreshBotSessions();await refreshExecutionLogs();});}
function renderBotSessions(){const tbody=document.querySelector('#bot-sessions-table tbody');if(!tbody)return;const rows=DASHBOARD_CACHE.botSessions||[];if(!rows.length){tbody.innerHTML='<tr><td colspan="9"><small class="hint">No hay bots activos todavía. Activa uno desde "Ejecutar estrategia".</small></td></tr>';return;}tbody.innerHTML=rows.map((item)=>`<tr data-session-id="${item.id}"><td>${item.connector_label||'-'}</td><td>${item.platform||'-'} (${item.mode||'-'})</td><td>${(item.symbols||[]).join(', ')||'-'}</td><td>${strategyName(item.strategy_slug)}<br><small class="hint">TF ${item.timeframe||'-'}</small></td><td>${Number(item.capital_per_operation||0).toFixed(4)}</td><td>Cada ${item.interval_minutes||5} min</td><td>${botStatusLabel(item)}</td><td>${formatLocalDateTime(item.last_run_at)}</td><td><div class="row-wrap"><button class="btn btn-sm" onclick="setBotSessionActive(${item.id}, ${!item.is_active})">${item.is_active?'Pausar':'Reanudar'}</button><button class="btn btn-sm" onclick="editBotSession(${item.id})">Editar</button><button class="btn btn-sm" onclick="deleteBotSession(${item.id})">Eliminar</button></div></td></tr>`).join('');}
async function refreshBotSessions(){try{const rows=await api('/api/bot-sessions');DASHBOARD_CACHE.botSessions=Array.isArray(rows)?rows:[];renderBotSessions();renderLiveStrategiesPanel();renderQuantumStatus();}catch(err){const tbody=document.querySelector('#bot-sessions-table tbody');if(tbody)tbody.innerHTML=`<tr><td colspan="9"><div class="status-msg status-error">No se pudieron cargar bots: ${parseApiError(err)}</div></td></tr>`;}}
function setRunFeedback(message,type='ok'){const box=document.getElementById('run-feedback');if(!box)return;box.hidden=false;box.textContent=message;box.classList.remove('status-ok','status-error');box.classList.add(type==='error'?'status-error':'status-ok');}
async function activateBotFromForm(){const form=document.getElementById('run-form');if(!form)return;const fd=new FormData(form);const connectorIds=selectedRunConnectorIds();if(!connectorIds.length){setRunFeedback('Selecciona un conector para activar bot 24/7.','error');return;}const timeframe=String(fd.get('timeframe')||'5m');const payload={connector_id:connectorIds[0],symbols:parseCsv(fd.get('symbols')),timeframe,strategy_slug:fd.get('strategy_slug'),risk_per_trade:Number(fd.get('risk_per_trade_percent')),min_ml_probability:Number(fd.get('min_ml_probability_percent')),use_live_if_available:fd.get('use_live_if_available')==='on',take_profit_mode:fd.get('take_profit_mode'),take_profit_value:Number(fd.get('take_profit_value')),stop_loss_mode:fd.get('stop_loss_mode'),stop_loss_value:Number(fd.get('stop_loss_value')),trailing_stop_mode:fd.get('trailing_stop_mode'),trailing_stop_value:Number(fd.get('trailing_stop_value')),indicator_exit_enabled:fd.get('indicator_exit_enabled')==='on',indicator_exit_rule:fd.get('indicator_exit_rule'),interval_minutes:timeframeToMinutes(timeframe)};try{const result=await api('/api/bot-sessions',{method:'POST',body:JSON.stringify(payload)});setRunFeedback(`Bot 24/7 activado. Sesión #${result.session_id}.`);await refreshBotSessions();await refreshExecutionLogs();}catch(err){setRunFeedback(parseApiError(err),'error');}}

function renderExecutionLogs(){const tbody=document.querySelector('#execution-logs-table tbody');if(!tbody)return;const rows=(DASHBOARD_CACHE.executionLogs||[]).slice(0,EXECUTION_LOG_LIMIT);if(!rows.length){tbody.innerHTML='<tr><td colspan="8"><small class="hint">Sin logs todavía. Ejecuta una estrategia para comenzar.</small></td></tr>';setExecutionLogsMeta(`Auto-refresh cada 5 minutos · Mostrando últimos ${EXECUTION_LOG_LIMIT} logs · Sin datos todavía.`);return;}tbody.innerHTML=rows.map((item)=>`<tr><td>${formatLocalDateTime(item.created_at)}</td><td>${item.symbol||'-'}</td><td>${item.timeframe||item?.notes?.timeframe||'-'}</td><td>${item.signal||'-'}</td><td>${decisionLabel(item)}</td><td>${item.status||'-'}</td><td>${Number(item.ml_probability||0).toFixed(3)}</td><td><small>${candleToText(candleFromNotes(item?.notes))}</small></td></tr>`).join('');setExecutionLogsMeta(`Auto-refresh cada 5 minutos · Mostrando ${rows.length} de ${EXECUTION_LOG_LIMIT} logs · Última actualización: ${formatLocalTimeNow()}`);}
async function refreshExecutionLogs(){try{const logs=await api(`/api/execution-logs?limit=${EXECUTION_LOG_LIMIT}`);DASHBOARD_CACHE.executionLogs=Array.isArray(logs)?logs:[];renderExecutionLogs();renderDecisionTelemetry();renderQuantumStatus();}catch(err){setExecutionLogsMeta(`Auto-refresh cada 5 minutos · Error al refrescar: ${parseApiError(err)}`);const tbody=document.querySelector('#execution-logs-table tbody');if(tbody)tbody.innerHTML=`<tr><td colspan="8"><div class="status-msg status-error">No se pudieron cargar logs: ${parseApiError(err)}</div></td></tr>`;}}

async function fetchOrFallback(path,fallback){try{return await api(path);}catch(err){console.warn(`[dashboard] ${path} failed`,err);return typeof fallback==='function'?fallback(err):fallback;}}

async function refreshDashboard(){const [connectors,data,trades,executionLogs,botSessions]=await Promise.all([fetchOrFallback('/api/connectors',[]),fetchOrFallback('/api/dashboard',{total_connectors:0,enabled_connectors:0,total_trades:0,realized_pnl:0,platforms:{},winning_trades:0,losing_trades:0}),fetchOrFallback('/api/trades',[]),fetchOrFallback(`/api/execution-logs?limit=${EXECUTION_LOG_LIMIT}`,[]),fetchOrFallback('/api/bot-sessions',[])]);DASHBOARD_CACHE={trades:Array.isArray(trades)?trades:[],summary:data||{},executionLogs:Array.isArray(executionLogs)?executionLogs:[],botSessions:Array.isArray(botSessions)?botSessions:[],connectors:Array.isArray(connectors)?connectors:[]};const statConnectors=document.getElementById('stat-connectors');if(statConnectors)statConnectors.textContent=Number(data?.total_connectors||0);const statEnabled=document.getElementById('stat-enabled');if(statEnabled)statEnabled.textContent=Number(data?.enabled_connectors||0);const statTrades=document.getElementById('stat-trades');if(statTrades)statTrades.textContent=Number(data?.total_trades||0);const statPnl=document.getElementById('stat-pnl');if(statPnl)statPnl.textContent=Number(data?.realized_pnl||0);const runSelect=document.getElementById('run-connector-select');if(runSelect){runSelect.innerHTML=(DASHBOARD_CACHE.connectors||[]).filter(c=>c&&c.is_enabled).map(c=>`<option value="${c.id}" data-market-type="${c.market_type||'spot'}">${c.label} (${c.platform} - ${c.market_type||'spot'})</option>`).join('');runSelect.onchange=()=>{renderStrategySelect();};}allowedPlatforms().forEach((platform)=>{const el=document.getElementById(`list-${platform}`);if(el)el.innerHTML=(DASHBOARD_CACHE.connectors||[]).filter(c=>c&&c.platform===platform).map(c=>`<div class="connector-item"><div class="row-between"><strong>${c.label||'Conector'}</strong><span class="pill tiny ${c.is_enabled?'pill-on':'pill-off'}">${c.is_enabled?'Activo':'Inactivo'}</span></div><div class="connector-meta"><span>Modo: ${c.mode||'-'}</span><span>Mercado: ${c.market_type||'-'}</span><span>Símbolos: ${(Array.isArray(c.symbols)?c.symbols:[]).join(', ')||'-'}</span></div><div style="margin-top:10px;display:flex;gap:8px;"><button class="btn" onclick="testConnector(${c.id})">Test</button><button class="btn" onclick="deleteConnector(${c.id})">Eliminar</button></div></div>`).join('')||'<small class="hint">Sin conectores todavía.</small>';});const tradesForCharts=DASHBOARD_CACHE.trades||[];const pnlByPlatform={};let cumulative=0;const cumulativeLabels=[];const cumulativeValues=[];tradesForCharts.slice().reverse().forEach((t,i)=>{const key=t.platform||'other';pnlByPlatform[key]=(pnlByPlatform[key]||0)+(Number(t.pnl)||0);cumulative+=(Number(t.pnl)||0);cumulativeLabels.push(String(i+1));cumulativeValues.push(Number(cumulative.toFixed(4)));});const pnlCanvas=document.getElementById('pnl-platform-chart');if(pnlCanvas){if(window.pnlPlatformChart)window.pnlPlatformChart.destroy();window.pnlPlatformChart=new Chart(pnlCanvas,{type:'bar',data:{labels:Object.keys(pnlByPlatform),datasets:[{label:'PNL',data:Object.values(pnlByPlatform),backgroundColor:'#38bdf8'}]},options:{plugins:{legend:{labels:{color:'#f4f7fb'}}},scales:{x:{ticks:{color:'#f4f7fb'}},y:{ticks:{color:'#f4f7fb'}}}}});}const winLossCanvas=document.getElementById('win-loss-chart');if(winLossCanvas){if(window.winLossChart)window.winLossChart.destroy();window.winLossChart=new Chart(winLossCanvas,{type:'pie',data:{labels:['Ganadas','Perdidas','Neutras'],datasets:[{data:[Number(data?.winning_trades||0),Number(data?.losing_trades||0),Math.max(0,Number(data?.total_trades||0)-Number(data?.winning_trades||0)-Number(data?.losing_trades||0))],backgroundColor:['#22c55e','#ef4444','#94a3b8']}]},options:{plugins:{legend:{labels:{color:'#f4f7fb'}}}}});}const cumulativeCanvas=document.getElementById('pnl-cumulative-chart');if(cumulativeCanvas){if(window.cumulativePnlChart)window.cumulativePnlChart.destroy();window.cumulativePnlChart=new Chart(cumulativeCanvas,{type:'line',data:{labels:cumulativeLabels,datasets:[{label:'PNL acumulado',data:cumulativeValues,borderColor:'#f59e0b',backgroundColor:'rgba(245,158,11,.2)',fill:true,tension:0.3}]},options:{plugins:{legend:{labels:{color:'#f4f7fb'}}},scales:{x:{ticks:{color:'#f4f7fb'}},y:{ticks:{color:'#f4f7fb'}}}}});}renderTrades();renderEconomicSummary();renderBotSessions();renderLiveStrategiesPanel();renderExecutionLogs();syncExecutiveBadge();renderDecisionTelemetry();renderQuantumStatus();}


async function refreshMarketBoard(){const context=document.getElementById('market-board-context');const range=document.getElementById('market-history-range')?.value||'day';const platform='binance';const query=new URLSearchParams({limit:'10',platform,range});if(context)context.textContent=range==='day'?'Top movimientos del día en pares USDT.':`Top movimientos (${range==='week'?'semana':'mes'}) en pares USDT.`;try{const rows=await api(`/api/market/top-strength?${query.toString()}`);const tbody=document.querySelector('#market-movers-table tbody');if(tbody){tbody.innerHTML=rows.map((row,index)=>`<tr><td>${index+1}</td><td>${row.symbol}</td><td>${Number(row.price||0).toFixed(4)}</td><td class="${Number(row.change_percent||0)>=0?'ticker-up':'ticker-down'}">${Number(row.change_percent||0).toFixed(2)}%</td><td>${Number(row.volume||0).toFixed(2)}</td></tr>`).join('');}}catch(err){const tbody=document.querySelector('#market-movers-table tbody');if(tbody)tbody.innerHTML=`<tr><td colspan="5" class="status-msg status-error">No se pudo cargar mercado: ${parseApiError(err)}</td></tr>`;}}

async function runHeartbeat(){const out=document.getElementById('heartbeat-output');if(!out)return;out.innerHTML='<small class="hint">Validando conectores...</small>';try{const data=await api('/api/heartbeat');out.innerHTML=data.checks.length?data.checks.map(item=>`<div class="connector-item compact"><div class="row-between"><strong>${item.label} (${item.platform})</strong><span class="pill tiny ${item.ok?'pill-on':'pill-off'}">${item.ok?'OK':'Error'}</span></div><small class="hint">${item.message}</small></div>`).join(''):'<small class="hint">No hay conectores activos para validar.</small>';}catch(err){out.innerHTML=`<div class="status-msg status-error">${parseApiError(err)}</div>`;}}
async function testConnector(id){try{const out=await api(`/api/connectors/${id}/test`,{method:'POST'});alert(`${out.status}: ${out.message}`);}catch(err){alert(parseApiError(err));}}
